local FEEDBACK_COOLDOWN, lastFeedback = 20, 0
local ERRMAP = {
    empty = "El mensaje está vacío.", no_links = "No se permiten enlaces.",
    too_long = "El mensaje es demasiado largo (máximo 500 caracteres).", rate_limited = "Alcanzaste el límite de 3 mensajes. Inténtalo más tarde.",
    busy = "El servidor está ocupado. Inténtalo de nuevo.", banned = "No tienes permiso para enviar comentarios.",
    discord_error = "Error al enviar. Inténtalo de nuevo.", network = "Error de red.",
    no_request = "Tu ejecutor no puede enviar solicitudes.", bad_response = "El servidor devolvió una respuesta inesperada.",
    unreachable = "Tu ejecutor no puede conectar con el servidor (error TLS). Prueba con otro ejecutor.",
}
local FG = Tabs.Suggest:AddLeftGroupbox("Sugerencias / Ayuda", "message-square")
FG:AddDropdown("FeedbackType", {Text = "Tipo", Values = {"Suggestion", "Bug", "Help"}, Default = "Suggestion", Callback = function() end})
FG:AddInput("FeedbackMsg", {Default = "", Numeric = false, Finished = false, ClearTextOnFocus = false, Text = "Mensaje", Placeholder = "Escribe tu mensaje (máximo 500 caracteres, sin enlaces)"})
local fbStatus = FG:AddLabel("", true)
FG:AddButton({
    Text = "📨 Send",
    Func = function()
        local now = tick()
        if now - lastFeedback < FEEDBACK_COOLDOWN then
            safeSet(fbStatus, string.format("Espera %d segundos antes de enviar de nuevo.", math.ceil(FEEDBACK_COOLDOWN - (now - lastFeedback))))
            return
        end
        local ftype = tostring((Options.FeedbackType and Options.FeedbackType.Value) or "Suggestion"):lower()
        local msg   = M.trim((Options.FeedbackMsg and Options.FeedbackMsg.Value) or "")
        if msg == "" then safeSet(fbStatus, "El mensaje está vacío."); return end
        if #msg > 500 then safeSet(fbStatus, "El mensaje es demasiado largo (máximo 500 caracteres)."); return end
        local low = msg:lower()
        if low:find("http", 1, true) or low:find("discord.gg", 1, true) or low:find("www.", 1, true) or low:find(".gg/", 1, true) then
            safeSet(fbStatus, "No se permiten enlaces."); return
        end
        safeSet(fbStatus, "Enviando...")
        task.spawn(function()
            local sok, err = M.sendFeedback(ftype, msg, (preCheck and preCheck.session_token) or "")
            if sok then
                lastFeedback = tick()
                safeSet(fbStatus, "✅ Enviado. ¡Gracias!")
                pcall(function() Options.FeedbackMsg:SetValue("") end)
                Library:Notify({Title = "COMBOWICK", Description = "Tu comentario fue enviado. ¡Gracias!", Time = 3})
            else
                safeSet(fbStatus, ERRMAP[err] or ("Error al enviar: " .. tostring(err)))
            end
        end)
    end,
})
FG:AddLabel("Máximo 3 mensajes por hora. Sin enlaces ni menciones.", true)

