task.spawn(function()
    safeSet(statusLabel, "Autenticando...")

    local result = M.withRetry(M.checkSession, M.hwid)

    if result == nil then
        safeSet(statusLabel, "Estado: Fallido")
        Library:Notify({Title="COMBOWICK", Description="La verificación de la sesión falló.", Time=5})

    elseif result.status == "allowed" or result.status == "session_active" then
        if result.disabled then
            safeSet(statusLabel, "⛔ Juego deshabilitado")
            safeSet(hintLabel, "La versión gratuita no está disponible aquí. Consigue una clave.")
            Library:Notify({Title="COMBOWICK", Description="La versión gratuita está deshabilitada para este juego. Usa una clave.", Time=6})
            return
        end
        local token = result.session_token
        if type(token) ~= "string" or #token < 20 then
            safeSet(statusLabel, "Estado: Fallido")
        else
            safeSet(statusLabel, "Estado: Autenticado")
            Library:Notify({Title="COMBOWICK", Description="Estás autenticado.", Time=3})
            _G.COMBOWICK_FREE   = true
            _G.COMBOWICK_ACTIVE = true
            local remaining = tonumber(result.remaining) or 0
            task.spawn(function()
                while remaining > 0 do
                    local fmt = M.formatTime(remaining)
                    safeSet(timerLabel, string.format("Tiempo restante: %s", fmt))
                    safeSet(lSession, string.format("Tiempo de sesión: %s", fmt))
                    task.wait(1); remaining = remaining - 1
                end
                safeSet(timerLabel, "La sesión ha expirado.")
                safeSet(lSession, "Tiempo de sesión: expirado")
                _G.COMBOWICK_ACTIVE = false
                pcall(function() Library:Unload() end)
                task.wait(0.5)
                M.reloadExist()
            end)
            local scriptUrl = M.getScriptForGame(token)
            if M.loadFreeScript(scriptUrl, token) then task.wait(2); pcall(function() Library:Unload() end) end
        end

    elseif result.status == "cooldown" then
        local remaining = tonumber(result.remaining) or 0
        safeSet(statusLabel, "En enfriamiento")
        safeSet(hintLabel, "Consigue una clave de 11 horas o espera a que termine el enfriamiento.")
        Library:Notify({Title="COMBOWICK", Description="Estás en enfriamiento. Consigue una clave para saltar la espera.", Time=6})
        task.spawn(function()
            while remaining > 0 do
                local fmt = M.formatTime(remaining)
                safeSet(timerLabel, string.format("Enfriamiento: %s", fmt))
                safeSet(lCooldown, string.format("Enfriamiento: %s", fmt))
                task.wait(1); remaining = remaining - 1
            end
            safeSet(timerLabel, "El enfriamiento ha terminado.")
            safeSet(lCooldown, "Enfriamiento: terminado")
            safeSet(hintLabel, "")
            Library:Notify({Title="COMBOWICK", Description="El enfriamiento ha terminado. Recargando...", Time=3})
            pcall(function() Library:Unload() end)
            task.wait(0.5)
            M.reloadExist()
        end)

    elseif result.status == "throttled" then
        local remaining = tonumber(result.remaining) or 0
        safeSet(statusLabel, "Demasiadas solicitudes")
        safeSet(hintLabel, "Demasiadas solicitudes. Por favor, espera.")
        Library:Notify({Title="COMBOWICK", Description="Demasiadas solicitudes. Espera un momento.", Time=5})
        task.spawn(function()
            while remaining > 0 do
                safeSet(timerLabel, string.format("Reintentar en %s", M.formatTime(remaining)))
                task.wait(1); remaining = remaining - 1
            end
            safeSet(timerLabel, "Recargando...")
            safeSet(hintLabel, "")
            pcall(function() Library:Unload() end)
            task.wait(0.5)
            M.reloadExist()
        end)

    elseif result.status == "disabled" then
        safeSet(statusLabel, "Servicio en pausa")
        safeSet(hintLabel, "COMBOWICK está temporalmente fuera de servicio.")
        Library:Notify({Title="COMBOWICK", Description="El servicio está deshabilitado en este momento. Inténtalo más tarde.", Time=6})

    elseif result.status == "banned" then
        safeSet(statusLabel, "Baneado")
        Library:Notify({Title="COMBOWICK", Description="Estás baneado.", Time=5})

    elseif result.status == "game_not_allowed" then
        safeSet(statusLabel, "🚫 Juego no compatible")
        safeSet(hintLabel, "Este juego aún no es compatible. Las claves premium siguen funcionando si hay un script disponible.")
        Library:Notify({Title="COMBOWICK", Description="Este juego aún no es compatible.", Time=6})

    else
        safeSet(statusLabel, "Error")
        safeSet(hintLabel, "No se pudo conectar con el servidor. Vuelve a ejecutar el script.")
        Library:Notify({Title="COMBOWICK", Description=tostring(result.message or "Ocurrió un error desconocido."), Time=5})
    end
end)

